#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        char s[55]; scanf("%s", s);
        int n = strlen(s);
        int cnt[26] = {0};
        for (int i = 0; i < n; ++i) cnt[s[i]-'a']++;
        int ok = 0;
        for (int i = 0; i < 26; ++i) {
            int sum = 0;
            for (int j = 0; j < 26; ++j) if (j != i) sum += cnt[j];
            if (cnt[i] == sum) { ok = 1; break; }
        }
        printf("%s\n", ok ? "YES" : "NO");
    }
    return 0;
}

