import sys

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0])
    out = []
    for i in range(1, T+1):
        s = data[i].strip()
        n = len(s)
        freq = [0]*26
        for ch in s:
            freq[ord(ch)-97] += 1
        ok = False
        for i in range(26):
            sum_other = sum(freq[:i] + freq[i+1:])
            if freq[i] == sum_other:
                ok = True
                break
        out.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

